// Three-level hierarchy for restaurant script
const hierarchy = {
  task: 'RESTAURANT_SCRIPT',
  options: [
    {
      name: 'ENTER',
      operator: 'PTRANS(self, outside→restaurant)',
      primitives: ['walk', 'open_door', 'step_through']
    },
    {
      name: 'SIT',
      operator: 'PTRANS(self, standing→seated)',
      primitives: ['walk_to_table', 'pull_chair', 'lower_body']
    },
    {
      name: 'ORDER',
      operator: 'MTRANS(desire, self→waiter)',
      primitives: ['get_attention', 'speak_words', 'point_menu']
    },
    {
      name: 'EAT',
      operator: 'INGEST(food, self)',
      primitives: ['lift_fork', 'cut', 'chew', 'swallow']
    },
    {
      name: 'PAY',
      operator: 'ATRANS(money, self→restaurant)',
      primitives: ['get_check', 'count_money', 'hand_over']
    }
  ]
};

return `TASK: ${hierarchy.task}\n\n` +
  hierarchy.options.map(opt => 
    `▸ ${opt.name}\n  Operator: ${opt.operator}\n  Primitives: [${opt.primitives.join(', ')}]`
  ).join('\n\n');
